class SQSWorker:
    def __init__(
        self,
        queue_url: str,
        region_name: str = 'us-east-1',
        secret_key: Optional[str] = None,
        max_messages: int = 10,
        wait_time_seconds: int = 20,
        visibility_timeout: int = 30
    ):
        self.queue_url = queue_url
        self.max_messages = max_messages
        self.wait_time_seconds = wait_time_seconds
        self.visibility_timeout = visibility_timeout
        
        self.sqs_client = boto3.client('sqs', region_name=region_name)
        self.validator = MessageValidator(secret_key)
        self.message_handler = MessageHandler()
        
        self._register_default_handlers()
    
    def _register_default_handlers(self):
        self.message_handler.register_handler('email_notification', handle_email_notification)
        self.message_handler.register_handler('data_processing', handle_data_processing)
        self.message_handler.register_handler('report_generation', handle_report_generation)
        self.message_handler.register_handler('file_upload', handle_file_upload)
        self.message_handler.register_handler('user_registration', handle_user_registration)
        self.message_handler.register_handler('payment_processing', handle_payment_processing)
    
    def register_handler(self, message_type: str, handler: Callable):
        self.message_handler.register_handler(message_type, handler)
    
    def poll_messages(self):
        try:
            response = self.sqs_client.receive_message(
                QueueUrl=self.queue_url,
                MaxNumberOfMessages=self.max_messages,
                WaitTimeSeconds=self.wait_time_seconds,
                VisibilityTimeout=self.visibility_timeout,
                AttributeNames=['All'],
                MessageAttributeNames=['All']
            )
            
            return response.get('Messages', [])
        
        except ClientError as e:
            logger.error(f"Error polling messages from SQS: {str(e)}")
            return []
    
    def process_message(self, message: Dict[str, Any]) -> bool:
        try:
            message_body = message['Body']
            receipt_handle = message['ReceiptHandle']
            
            try:
                parsed_message = json.loads(message_body)
            except json.JSONDecodeError:
                logger.error("Invalid JSON in message body")
                return False
            
            message_attributes = message.get('MessageAttributes', {})
            signature = message_attributes.get('Signature', {}).get('StringValue', '')
            
            if signature and not self.validator.validate_signature(message_body, signature):
                logger.error("Message signature validation failed")
                return False
            
            if not self.validator.validate_message_structure(parsed_message):
                logger.error("Message structure validation failed")
                return False
            
            message_type = parsed_message['type']
            payload = self.validator.sanitize_payload(parsed_message['payload'])
            
            success = self.message_handler.handle_message(message_type, payload)
            
            if success:
                self.delete_message(receipt_handle)
                logger.info(f"Successfully processed message of type: {message_type}")
            else:
                logger.warning(f"Failed to process message of type: {message_type}")
            
            return success
        
        except Exception as e:
            logger.error(f"Error processing message: {str(e)}")
            return False
    
    def delete_message(self, receipt_handle: str):
        try:
            self.sqs_client.delete_message(
                QueueUrl=self.queue_url,
                ReceiptHandle=receipt_handle
            )
            logger.info("Message deleted from queue")
        except ClientError as e:
            logger.error(f"Error deleting message: {str(e)}")
    
    def run(self, continuous: bool = True):
        logger.info(f"Starting SQS worker for queue: {self.queue_url}")
        
        while True:
            messages = self.poll_messages()
            
            if messages:
                logger.info(f"Received {len(messages)} messages")
                
                for message in messages:
                    self.process_message(message)
            else:
                logger.info("No messages received")
            
            if not continuous:
                break


